{
  "model": "opusplan",
  "hooks": {
    "PreToolUse": [
      {
        "matcher": "Edit|Write",
        "hooks": [
          {
            "type": "command",
            "command": "f=$(jq -r '.tool_input.file_path // \"\"'); echo \"$f\" | grep -qE \"src/pages/(console|process|designer)|src/shared/graphics\" && echo \"$f\" | grep -qv \"CLAUDE\\.md$\" && printf '{\"hookSpecificOutput\":{\"hookEventName\":\"PreToolUse\",\"additionalContext\":\"HISTORICAL SPEC EXISTS: This file has a historical spec in /home/io/spec_docs/ (now archived — see spec_docs/ARCHIVE.md). Non-negotiables and architectural constraints are mostly still valid; verify against actual code before acting on specifics. console→console-implementation-spec.md | process→process-implementation-spec.md | designer→designer-implementation-spec.md + designer-ui-prompt.md | graphics→graphics-scene-graph-implementation-spec.md + display-elements-implementation-spec.md\"}}' || true",
            "statusMessage": "Checking for historical spec..."
          }
        ]
      }
    ],
    "PostToolUse": [
      {
        "matcher": "Edit|Write",
        "hooks": [
          {
            "type": "command",
            "command": "f=$(jq -r '.tool_input.file_path // \"\"'); echo \"$f\" | grep -qE \"(^|/)package\\.json$|(^|/)Cargo\\.toml$\" && printf '{\"hookSpecificOutput\":{\"hookEventName\":\"PostToolUse\",\"additionalContext\":\"DEPENDENCY FILE CHANGED: %s was modified. If any dependencies were added or removed, update docs/PROJECT_REFERENCE.md to keep the tech stack current.\"}}' \"$f\" || true",
            "statusMessage": "Checking for dependency changes..."
          }
        ]
      }
    ]
  },
  "statusLine": {
    "type": "command",
    "command": "bash ~/.claude/statusline-command.sh"
  },
  "enabledPlugins": {
    "typescript-lsp@claude-plugins-official": true,
    "rust-analyzer-lsp@claude-plugins-official": true,
    "frontend-design@claude-plugins-official": true,
    "pr-review-toolkit@claude-plugins-official": true,
    "security-guidance@claude-plugins-official": true,
    "code-review@claude-plugins-official": true,
    "claude-code-setup@claude-plugins-official": true,
    "context7@claude-plugins-official": true,
    "claude-md-management@claude-plugins-official": true,
    "feature-dev@claude-plugins-official": true,
    "playwright@claude-plugins-official": true
  },
  "autoDreamEnabled": true,
  "skipDangerousModePermissionPrompt": true
}

